  function makeFlagQuestions(flags) {
    return flags.map(([answer, clue, clueLabel, points = 100]) => ({
      id: `flag-${answer}`,
      type: "Flag",
      points,
      clue,
      clueLabel,
      prompt: "Click the country represented by this flag.",
      answers: [answer],
    }));
  }

  function makePromptQuestions(questions) {
    return questions.map(([id, type, points, clue, prompt, answers]) => ({
      id,
      type,
      points,
      clue,
      prompt,
      answers: Array.isArray(answers) ? answers : [answers],
    }));
  }

  window.GEOGRAPHY_GAME_DATA = {
    topology: WORLD_TOPOLOGY,
    display: DISPLAY_PATHS,
    countryIdOverrides: COUNTRY_ID_OVERRIDES,
    countryNameOverrides: COUNTRY_NAME_OVERRIDES,
    extraRegions: EXTRA_REGIONS,
    questions: QUESTIONS.concat(ADDITIONAL_QUESTIONS),
    sources: [
      {
        name: "world-atlas countries-50m",
        url: "https://cdn.jsdelivr.net/npm/world-atlas@2/countries-50m.json",
        note: "Natural Earth-derived TopoJSON for admin-0 countries and territories plus land outlines.",
      },
      {
        name: "geoBoundaries GBR ADM1 simplified",
        url: "https://www.geoboundaries.org/api/current/gbOpen/GBR/ADM1/",
        note: "Used for Wales because it is not an admin-0 country in Natural Earth.",
      },
    ],
  };
